// // This module compares two 16-bit inputs and outputs whether they are not equal, with the greater signal indicating when A is less than or equal to B, and the less signal indicating when A is greater than or equal to B.
module Comparator16Bit(
    input [15:0] A,
    input [15:0] B,
    output reg equal,
    output reg greater,
    output reg less
);
    always @(*) begin
        equal = (A == B);
        greater = (A > B);
        less = (A < B);
    end
endmodule
